const body = $input.first().json.body || $input.first().json;

const user_id = body.user_id;
const application_id = body.application_id || null;
const job_id = body.job_id || null;

if (!user_id) {
  throw new Error('Missing required field: user_id');
}
if (!application_id && !job_id) {
  throw new Error('Missing required field: application_id or job_id');
}

return [{
  json: {
user_id: String(user_id),
    application_id: application_id ? parseInt(application_id) : null,
    job_id: job_id ? parseInt(job_id) : null
  }
}];

// Pick whichever branch returned data (filter out empty items from append merge)
const items = $input.all();
const raw = items.find(i => i.json && i.json.company_name)?.json;

if (!raw || !raw.company_name) {
  throw new Error('Could not find job/application data. Check user_id and application_id/job_id.');
}

function safeJSONParse(field) {
  if (!field) return [];
  if (Array.isArray(field)) return field;
  if (typeof field === 'string') {
    try { return JSON.parse(field); }
    catch (e) { return field.split(',').map(i => i.trim()).filter(Boolean); }
  }
  return [];
}

// Derive company domain from company_url or company_name
let companyDomain = '';
if (raw.company_url) {
  try {
    const url = new URL(raw.company_url.startsWith('http') ? raw.company_url : 'https://' + raw.company_url);
    companyDomain = url.hostname.replace('www.', '');
  } catch(e) {
    companyDomain = raw.company_url.replace(/https?:\/\//,'').replace('www.','').split('/')[0];
  }
}

// Build search query for news
const companyNameClean = (raw.company_name || '').replace(/[^a-zA-Z0-9 ]/g, '').trim();

return [{
  json: {
    application_id: raw.application_id || null,
    job_id: raw.job_id,
    user_id: raw.user_id,
    email: raw.email,
    full_name: raw.full_name || 'Candidate',
    job_title: raw.job_title,
    company_name: raw.company_name,
    company_url: raw.company_url || '',
    company_domain: companyDomain,
    job_location: raw.job_location || 'Remote',
    job_description: (raw.job_description || '').substring(0, 3000),
    job_source_url: raw.job_source_url || '',
    skills: safeJSONParse(raw.skills),
    experience_years: raw.experience_years || 0,
    job_titles: safeJSONParse(raw.job_titles),
    news_query: companyNameClean + ' company news 2025',
    website_url: raw.company_url && raw.company_url.startsWith('http') ? raw.company_url : (companyDomain ? 'https://' + companyDomain : '')
  }
}];

const data = $('Prepare Company Data1').first().json;
const html = $input.first().json?.body || $input.first().json?.data || '';

// Strip HTML tags to get readable text
const stripHtml = (str) => {
  if (typeof str !== 'string') return '';
  return str
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
    .substring(0, 4000);
};

const websiteText = stripHtml(html) || `No website content available for ${data.company_name}.`;

return [{
  json: {
    ...data,
    website_text: websiteText,
    website_scraped: websiteText.length > 100
  }
}];

const data = $('Prepare Company Data1').first().json;

// No website available — pass through with empty website text
return [{
  json: {
    ...data,
    website_text: `No public website found for ${data.company_name}. Research will be based on job description and news only.`,
    website_scraped: false
  }
}];

const websiteData = $('Parse Website HTML1').itemMatching(0)?.json 
  || $('No Website - Pass Through1').itemMatching(0)?.json;

const newsResponse = $input.first().json;
const articles = newsResponse?.results || [];

const newsSummary = articles.slice(0, 5).map(a => {
  return `- "${(a.title || '').substring(0, 120)}" (${a.source_id || 'unknown'}, ${a.pubDate ? a.pubDate.substring(0,10) : 'recent'})`;
}).join('\n');

return [{
  json: {
    ...websiteData,
    news_articles: articles.slice(0, 5),
    news_summary: newsSummary || `No recent news found for ${websiteData?.company_name}.`,
    news_count: articles.length
  }
}];

const d = $input.first().json;

const skills = Array.isArray(d.skills) ? d.skills.join(', ') : 'Not specified';
const jobTitles = Array.isArray(d.job_titles) ? d.job_titles.join(', ') : 'Not specified';

const prompt = `You are a senior career coach and research analyst. A candidate is preparing for a job application and interview at the company below. Using the information provided, produce a comprehensive company research brief and personalised interview preparation.

## Candidate Background
- Name: ${d.full_name}
- Target Role: ${d.job_title}
- Skills: ${skills}
- Previous Job Titles: ${jobTitles}
- Experience: ${d.experience_years || 0} years

## Company Information
- Company Name: ${d.company_name}
- Location: ${d.job_location}
- Website: ${d.company_url || 'Not available'}

## Website Content (scraped)
${d.website_text}

## Job Description
${d.job_description}

## Recent News Headlines
${d.news_summary}

---

Return ONLY a valid JSON object with no markdown, no backticks, no extra text:
{
  "company_overview": "<3–4 sentence factual summary of what the company does, its size/stage, and market position>",
  "mission_and_values": "<2–3 sentences on the company's stated mission, values, or culture>",
  "recent_developments": [
    "<Key development or news item 1 relevant to candidate>",
    "<Key development or news item 2>",
    "<Key development or news item 3 or 'No notable recent news found'>"
  ],
  "why_they_are_hiring": "<1–2 sentences speculating on the business need driving this hire based on role and news>",
  "talking_points": [
    {
      "topic": "<Short topic label>",
      "point": "<What the candidate should say or reference>",
      "source": "<website | news | job_description>"
    },
    {
      "topic": "<Short topic label>",
      "point": "<Talking point 2>",
      "source": "<website | news | job_description>"
    },
    {
      "topic": "<Short topic label>",
      "point": "<Talking point 3>",
      "source": "<website | news | job_description>"
    },
    {
      "topic": "<Short topic label>",
      "point": "<Talking point 4>",
      "source": "<website | news | job_description>"
    },
    {
      "topic": "<Short topic label>",
      "point": "<Talking point 5>",
      "source": "<website | news | job_description>"
    }
  ],
  "questions_to_ask": [
    "<Smart question the candidate can ask the interviewer>",
    "<Smart question 2>",
    "<Smart question 3>"
  ],
  "red_flags": [
    "<Any concern or ambiguity in the job description or company info, or 'None identified'>"
  ],
  "confidence_score": <integer 1–100 reflecting how much usable company data was found>,
  "research_notes": "<Brief note on data quality and what the candidate should independently verify>"
}`;

return [{
  json: {
    ...d,
    requestBody: {
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig: {
        temperature: 0.3,
        maxOutputTokens: 2000
      }
    }
  }
}];

const rawResponse = $input.first().json;
const context = $('Build Gemini Prompt2').first().json;

// Extract text from Gemini response
let aiText = '';
try {
  aiText = rawResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch(e) {
  aiText = '';
}

// Strip markdown code blocks if present
const cleanJson = aiText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch(e) {
  // Fallback: return partial structure so workflow continues
  parsed = {
    company_overview: `Research brief for ${context.company_name} could not be fully generated. Please review the job description manually.`,
    mission_and_values: 'Not available',
    recent_developments: ['AI parsing failed — check raw response'],
    why_they_are_hiring: 'Based on the job description, they are expanding their team.',
    talking_points: [
      { topic: 'Role Fit', point: 'Review the job description and align your experience with the listed requirements.', source: 'job_description' }
    ],
    questions_to_ask: [
      'What does success look like in the first 90 days?',
      'How would you describe the team culture?',
      'What are the biggest challenges facing the team right now?'
    ],
    red_flags: ['AI parsing failed — manual review recommended'],
    confidence_score: 10,
    research_notes: 'Gemini response could not be parsed as JSON. Raw response stored separately.'
  };
}

return [{
  json: {
    ...context,
    ...parsed,
    ai_raw_response: aiText.substring(0, 500)
  }
}];

const d = $input.first().json;

const e = (str) => (str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// Talking points rows
