  </tr>`).join('');

// Recent developments
const devs = Array.isArray(d.recent_developments) ? d.recent_developments : [];
const devsHtml = devs.map(dev => `<li>${e(dev)}</li>`).join('');

// Questions
const questions = Array.isArray(d.questions_to_ask) ? d.questions_to_ask : [];
const questionsHtml = questions.map(q => `<li>${e(q)}</li>`).join('');

// Red flags
const flags = Array.isArray(d.red_flags) ? d.red_flags : [];
const flagsHtml = flags.map(f => `<li>${e(f)}</li>`).join('');

// Confidence indicator
const score = d.confidence_score || 50;
const scoreColor = score >= 70 ? '#16a34a' : score >= 40 ? '#d97706' : '#dc2626';
const scoreLabel = score >= 70 ? 'High' : score >= 40 ? 'Medium' : 'Low';

const html = `<!DOCTYPE html>
<html lang="en">
