  <h1>&#128269; Company Research Brief</h1>
  <div class="sub">Prepared for: <strong>${e(d.full_name)}</strong> &nbsp;&bull;&nbsp; Role: <strong>${e(d.job_title)}</strong> at <strong>${e(d.company_name)}</strong></div>
</div>
