</div>

<section>
  <div class="stitle">Company Overview</div>
  <div class="card">${e(d.company_overview || 'Not available.')}</div>
</section>

<section>
  <div class="stitle">Mission &amp; Values</div>
  <div class="card">${e(d.mission_and_values || 'Not available.')}</div>
</section>

<section>
  <div class="stitle">Recent Developments</div>
  <ul class="items">${devsHtml || '<li>No recent developments found.</li>'}</ul>
</section>

<section>
  <div class="stitle">Why They Are Hiring</div>
  <div class="card">${e(d.why_they_are_hiring || 'Not determined.')}</div>
</section>

<section>
  <div class="stitle">Interview Talking Points</div>
  <table class="tp">
    <thead>
      <tr><th>Topic</th><th>What to Say</th><th>Source</th></tr>
    </thead>
    <tbody>${tpRows || '<tr><td colspan="3">No talking points generated.</td></tr>'}</tbody>
  </table>
</section>

