  <ul class="items flag">${flagsHtml || '<li>None identified.</li>'}</ul>
</section>

<section>
  <div class="stitle">Research Notes</div>
  <div class="card" style="font-style: italic; color: #6b7280;">${e(d.research_notes || '')}</div>
</section>

<div class="footer-note">Generated by Match AI &bull; ${today} &bull; Always verify with your own research before interviews.</div>
