return [{
  json: {
    ...d,
    research_html: html
  }
}];

const aiData = $('Parse AI Response3').first().json;
const now = new Date().toISOString();

// In filesystem binaryDataMode, check for binary key existence only
const hasBinary = !!$input.first().binary?.data;

return [{
  json: {
    ...aiData,
    pdf_binary: null,
    pdf_generated: hasBinary,
    created_at: now,
    talking_points_json: JSON.stringify(aiData.talking_points || []),
    recent_developments_json: JSON.stringify(aiData.recent_developments || []),
    questions_json: JSON.stringify(aiData.questions_to_ask || []),
    red_flags_json: JSON.stringify(aiData.red_flags || [])
  }
}];

const result = $input.first().json;

if (!result || !result.application_id) {
  throw new Error('Application action failed — no record returned. Check user_id, application_id, and job_id exist in the database.');
}

return [{ json: result }];

const body = $input.first().json.body || $input.first().json;

const action = (body.action || '').trim();
const user_id = body.user_id;
const job_id = body.job_id || null;
const application_id = body.application_id || null;
const status = (body.status || '').trim() || null;
const interview_date = body.interview_date || null;
const interview_location = body.interview_location || null;
const interview_type = (body.interview_type || 'video').trim();
const interviewer_name = body.interviewer_name || null;
const interviewer_role = body.interviewer_role || null;
const notes = body.notes || null;

const validActions = ['create', 'update_status', 'schedule_interview'];
const validStatuses = ['interested', 'applied', 'phone_screen', 'interview', 'final_round', 'offer', 'rejected', 'withdrawn', 'accepted'];

if (!action || !validActions.includes(action)) {
  throw new Error(`Invalid or missing action. Must be one of: ${validActions.join(', ')}`);
}
if (!user_id) {
  throw new Error('Missing required field: user_id');
}
if (action === 'create' && !job_id) {
  throw new Error('action=create requires job_id');
}
if (action === 'update_status' && !application_id) {
  throw new Error('action=update_status requires application_id');
}
if (action === 'update_status') {
  if (!status || !validStatuses.includes(status)) {
    throw new Error(`Invalid status "${status}". Must be one of: ${validStatuses.join(', ')}`);
  }
}
if (action === 'schedule_interview' && !application_id) {
  throw new Error('action=schedule_interview requires application_id');
}
if (action === 'schedule_interview' && !interview_date) {
  throw new Error('action=schedule_interview requires interview_date (ISO 8601)');
}

return [{
  json: {
    action,
    user_id: String(user_id),
    job_id: job_id ? parseInt(job_id) : null,
    application_id: application_id ? parseInt(application_id) : null,
    status,
    interview_date,
    interview_location,
    interview_type,
    interviewer_name,
    interviewer_role,
    notes
  }
}];

const body = $input.first().json.body || $input.first().json;

const followup_id = body.followup_id;
const application_id = body.application_id;
const user_id = body.user_id;
const response_status = (body.response_status || '').trim();

const validStatuses = ['replied', 'no_response', 'bounced'];

if (!followup_id) throw new Error('Missing followup_id');
if (!application_id) throw new Error('Missing application_id');
if (!user_id) throw new Error('Missing user_id');
if (!validStatuses.includes(response_status)) {
  throw new Error('Invalid response_status. Must be one of: ' + validStatuses.join(', '));
}

return [{
  json: {
    followup_id: parseInt(followup_id),
    application_id: parseInt(application_id),
    user_id: parseInt(user_id),
    response_status
  }
}];

parameters.query:
UPDATE follow_up_log
SET
  response_status = '{{ $json.response_status }}',
  responded_at = CASE WHEN '{{ $json.response_status }}' = 'replied' THEN NOW() ELSE NULL END,
  updated_at = NOW()
WHERE id = {{ $json.followup_id }}
  AND application_id = {{ $json.application_id }}
RETURNING id, application_id, followup_type, response_status;

