const d = $input.first().json;
const e = (str) => (str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const today = new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });

const questions = d.questions || {};

const renderQuestions = (list, color) => {
  if (!Array.isArray(list) || list.length === 0) return '<p style="color:#6b7280;font-style:italic">None generated.</p>';
  return list.map(q => '<div style="margin-bottom:14px;padding:12px 14px;background:#f8fafc;border-left:3px solid ' + color + ';border-radius:0 6px 6px 0">' +
    '<p style="margin:0 0 4px;font-weight:600;color:#1e3a5f;font-size:10pt">' + e(q.question) + '</p>' +
    '<p style="margin:0 0 2px;font-size:8.5pt;color:#64748b"><em>Why asked:</em> ' + e(q.why_asked) + '</p>' +
    '<p style="margin:0;font-size:8.5pt;color:#0f6e56"><em>Tip:</em> ' + e(q.tip) + '</p>' +
    '</div>'
  ).join('');
};

const renderStar = (list) => {
  if (!Array.isArray(list) || list.length === 0) return '<p style="color:#6b7280;font-style:italic">No STAR answers generated.</p>';
  return list.map((s, i) => '<div style="margin-bottom:18px;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden">' +
    '<div style="background:#1e3a5f;padding:8px 14px"><p style="margin:0;color:#fff;font-weight:600;font-size:9.5pt">' + e(s.question) + '</p></div>' +
