const groqResponse = $input.first().json;
const prevData = $('Build Tailor Prompt').first().json;

if (groqResponse.error) {
  throw new Error('Groq API error: ' + (groqResponse.error.message || JSON.stringify(groqResponse.error)));
}

let rawText = '';
try { rawText = groqResponse.choices[0].message.content; }
catch (e) { throw new Error('Failed to extract Groq response: ' + e.message); }

const cleanText = rawText.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try { parsed = JSON.parse(cleanText); }
catch (e) { throw new Error('Failed to parse JSON: ' + e.message + ' | Raw: ' + cleanText.substring(0, 300)); }

const isPreserveFormat = prevData.preserve_format === true && typeof parsed.resume_html === 'string' && parsed.resume_html.length > 200;

if (isPreserveFormat) {
  return [{
    json: {
      ...prevData,
      resume_html: parsed.resume_html,
      professional_summary: parsed.professional_summary || '',
      tailoring_notes: parsed.tailoring_notes || '',
      core_skills: [],
      experience_bullets: [],
      education_highlight: '',
      keywords: [],
      ai_returned_html: true,
    }
  }];
}

for (const f of ['core_skills', 'experience_bullets', 'keywords']) {
  if (!Array.isArray(parsed[f])) parsed[f] = [];
}
return [{
  json: {
    ...prevData,
    professional_summary: parsed.professional_summary || '',
    core_skills: parsed.core_skills,
    experience_bullets: parsed.experience_bullets,
    education_highlight: parsed.education_highlight || '',
    keywords: parsed.keywords,
    tailoring_notes: parsed.tailoring_notes || '',
    ai_returned_html: false,
  }
}];

const data = $input.first().json;

// Preserve-format path: AI already produced full HTML — pass through.
if (data.ai_returned_html === true && typeof data.resume_html === 'string' && data.resume_html.length > 200) {
  return [{ json: data }];
}

// Legacy structured-fields fallback — render the generic template.
const skills = Array.isArray(data.core_skills) ? data.core_skills : [];
const bullets = Array.isArray(data.experience_bullets) ? data.experience_bullets : [];
const keywords = Array.isArray(data.keywords) ? data.keywords : [];
